import{c as i,Q as l,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"关于那封信的内容，我就不","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/139-关于那封信的内容，我就不.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/139-关于那封信的内容，我就不.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/139-关于那封信的内容，我就不.md"};function o(s,a,n,_,m,d){return l(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"关于那封信的内容-我就不",tabindex:"-1"},[t("关于那封信的内容，我就不 "),e("a",{class:"header-anchor",href:"#关于那封信的内容-我就不","aria-label":'Permalink to "关于那封信的内容，我就不"'},"​")],-1),e("p",null,"关于那封信的内容，我就不再重复了。 正如我之前所说，驻扎在离此地大约5英里处圣马尔蒂诺的威尼斯军 队昨日已经撤离，并朝着维琴察的方向前进。据说，此番行动的原因是他 们在那里没能看到任何暴动的迹象，再考虑到法国人的因素，他们就没有 采取进一步的行动。正如我在上一封信中提到的，虽然法国人的数目很 少，但威尼斯军队还是不愿在法国人的地盘公然挑起敌对情绪，因为他们 不想激怒国王，使得国王对他们加大火力。没人胆敢推测，这一切的最终 结局将是如何。确实，众所周知，法国国王很想得到这个城市，城里的许 多贵族平民也希望如此，而皇帝此时看来还没有足够的力量去保卫这座城 市。情势不可能长久僵持，因为如果法国人不提供物资和军火补给，城中 的人民很快就要活活饿死。双方君主究竟将如何控制事态，只能根据事情 的进展来判断，因为目前还没有听到任何关于谈判的消息。诸位大人应该 可以从弗朗切斯科 ·潘多尔菲尼处得知更多有关此事的消息。 正如我之前信中所提及的，皇帝现在罗韦雷多附近的阿奇，据说他正 在那里招募军队，然后将前往这里，如果不是因为维琴察的麻烦，他现在 应该是在因斯普鲁克。威尼斯人的撤退很可能促使皇帝有目的地采取行 动，虽然预计陛下将很快和部队一起到达这里，但一切仍是未知。除非另 有命令，否则我将留在这里，因为无论皇帝现在何处，他都不希望与任何 使节或任何人接近。所以，原本在他身边的法国和阿拉贡的使节都已经被 遣回特伦特。我确信，为了弄清这些事情，我与其前往特伦特，还不如继 续留在这里。只有一件事情能够促使我前去特伦特，那就是根据协议皇帝 承诺给我们而还未兑现的权力。但因为我离开佛罗伦萨时，诸位大人对此 事并未提及，事后也没有写信说到这个问题，所以我不知道现在我前去申 明权力是否适宜。敬请诸位大人多多关照，保重再会。",-1),e("p",null,"维罗纳，1509年11月24日 仆尼科洛 · 马基雅维利，国务秘书 皮杰洛大人请求诸位大人留意他的服务以及他在罗马的事务。",-1),e("p",null,"政务与外交著作 Legazioni,commissaric,scrittidigoverno",-1)])])}const f=i(c,[["render",o]]);export{h as __pageData,f as default};
